document.addEventListener("DOMContentLoaded",function(){const toggle=document.getElementById("theme-toggle");const html=document.documentElement;const logo=document.getElementById("site-logo");const saved=localStorage.getItem("theme")||"dark";html.setAttribute("data-theme",saved);updateIcon(saved);updateLogo(saved);if(toggle){toggle.addEventListener("click",function(){const current=html.getAttribute("data-theme");const next=current==="dark"?"light":"dark";html.setAttribute("data-theme",next);localStorage.setItem("theme",next);updateIcon(next);updateLogo(next)})}function updateIcon(theme){const icon=toggle&&toggle.querySelector(".theme-icon");if(icon){icon.textContent=theme==="dark"?"☀️":"🌙"}}function updateLogo(theme){if(logo){if(theme==="dark"){logo.src="/static/core/images/logos/DARK_mode_LOGO.png"}else{logo.src="/static/core/images/logos/light_mode_LOGO.png"}}}function initCaseSelector(){const caseSelector=document.getElementById("case-selector");if(!caseSelector)return;fetch("/core/api/cases/").then(response=>response.json()).then(cases=>{const options=caseSelector.querySelectorAll("option:not(:first-child)");options.forEach(opt=>opt.remove());cases.forEach(caseItem=>{const option=document.createElement("option");option.value=caseItem.id;option.textContent=caseItem.name;caseSelector.appendChild(option)});const savedCaseId=localStorage.getItem("selectedCaseId");if(savedCaseId&&cases.some(c=>c.id==savedCaseId)){caseSelector.value=savedCaseId}}).catch(console.error);caseSelector.addEventListener("change",function(){const caseId=this.value;if(caseId){localStorage.setItem("selectedCaseId",caseId);window.location.href="/timeline/?case_id="+caseId}})}function initCollapsiblePanes(){console.log("initCollapsiblePanes called, buttons:",document.querySelectorAll(".collapse-button").length);const buttons=document.querySelectorAll(".collapse-button");if(buttons.length===0){console.log("No collapse buttons found in DOM");return}buttons.forEach(button=>{const targetId=button.getAttribute("data-target");const pane=targetId?document.getElementById(targetId):button.closest(".workspace-pane");if(!pane){console.log("No pane found for button",button);return}console.log("Setting up collapse for pane:",pane.id);const savedState=localStorage.getItem(pane.id+"_state");if(savedState==="collapsed"){pane.classList.add("collapsed");button.textContent="▶"}else{button.textContent="◀"}button.onclick=function(e){e.stopPropagation();console.log("Collapse clicked for:",pane.id);const isCollapsed=pane.classList.toggle("collapsed");localStorage.setItem(pane.id+"_state",isCollapsed?"collapsed":"expanded");button.textContent=isCollapsed?"▶":"◀"}})}function initTimelineSelector(){const timelineSelector=document.getElementById("timeline-selector");if(!timelineSelector)return;timelineSelector.addEventListener("change",function(){const filePath=this.value;if(filePath){localStorage.setItem("selectedTimelinePath",filePath);fetch(`/timeline/api/load-timeline/?file_path=${encodeURIComponent(filePath)}`).then(response=>response.json()).then(data=>{if(data.status==="success"){const headingEl=document.getElementById("timeline-heading");if(headingEl){headingEl.textContent=data.main_heading||"Legal Timeline"}window.location.href=`/timeline/?timeline_file=${encodeURIComponent(filePath)}`}}).catch(error=>{console.error("Failed to load timeline:",error)})}});const savedTimelinePath=localStorage.getItem("selectedTimelinePath");if(savedTimelinePath){const option=timelineSelector.querySelector(`option[value="${savedTimelinePath}"]`);if(option){timelineSelector.value=savedTimelinePath}}}initCaseSelector();initCollapsiblePanes();initTimelineSelector();initSubTimelineSelector()});function initSubTimelineSelector(){const subTimelineSelector=document.getElementById("sub-timeline-selector");if(!subTimelineSelector)return;const urlParams=new URLSearchParams(window.location.search);const timelineParam=urlParams.get("timeline");if(timelineParam){const option=subTimelineSelector.querySelector(`option[value="${timelineParam}"]`);if(option){subTimelineSelector.value=timelineParam;switchSubTimeline(timelineParam)}}subTimelineSelector.addEventListener("change",function(){switchSubTimeline(this.value)})}function formatDateMonth(dateStr){if(!dateStr)return"";const date=new Date(dateStr);if(isNaN(date.getTime()))return"";return date.toLocaleDateString("en-US",{month:"short"})}function formatDateDay(dateStr){if(!dateStr)return"";const parts=dateStr.split("-");if(parts.length>=3)return parseInt(parts[2],10).toString();const date=new Date(dateStr);if(isNaN(date.getTime()))return"";return date.getDate().toString()}function switchSubTimeline(timelineName){const timelineSelector=document.getElementById("sub-timeline-selector");const eventsContainer=document.getElementById("timeline-events-container");const headingEl=document.getElementById("timeline-heading");if(!timelineSelector||!eventsContainer||!window.timelinesData)return;const option=timelineSelector.querySelector(`option[value="${timelineName}"]`);if(option){timelineSelector.value=timelineName}if(headingEl&&timelineName!==headingEl.textContent){headingEl.textContent=timelineName}const url=new URL(window.location.href);url.searchParams.set("timeline",timelineName);window.history.pushState({},"",url);const events=window.timelinesData[timelineName]||[];if(events.length===0){eventsContainer.innerHTML='<div class="empty-timeline"><p>No events in this timeline.</p></div>';return}let html="";let currentYear=null;for(const event of events){const year=event.date?event.date.slice(0,4):"";if(year!==currentYear){currentYear=year;html+=`<div class="year-marker" data-year="${year}"><span class="year-text">${year}</span></div>`}const month=event.date?event.date.slice(5,7):"01";const day=event.date?event.date.slice(8,10):"01";html+=`
      <div class="timeline-event" data-date="${event.date||""}" data-year="${year}" data-section="${event.section||""}" onclick="openMarkdownEventPopup(this)">
        <div class="event-date-badge">
          <span class="date-month">${formatDateMonth(event.date)}</span>
          <span class="date-day">${formatDateDay(event.date)}</span>
          <span class="date-year">${year}</span>
        </div>
        <div class="event-content">
          <h3 class="event-title">${event.event||"Untitled"}</h3>
          <p class="event-category">${(event.category||"other").replace(/\b\w/,l=>l.toUpperCase())}</p>
          <p class="event-description">${(event.description||event.notes||"").substring(0,150)}</p>
        `;if(event.documents&&event.documents.length>0){html+=`
        <div class="event-docs-indicator">
          <span class="docs-icon">📎</span>
          <span class="docs-count">${event.documents.length} document(s)</span>
        </div>
      `}html+=`
        </div>
        <div class="event-connector"></div>
      </div>
    `}eventsContainer.innerHTML=html}let eventPopup=null;let currentEventId=null;let isAnalyzingWithAI=false;function initPopup(){eventPopup=document.getElementById("eventPopup");if(eventPopup){const overlay=eventPopup.querySelector(".popup-overlay");if(overlay){overlay.addEventListener("click",closeEventPopup)}document.addEventListener("keydown",function(e){if(e.key==="Escape"&&eventPopup.classList.contains("active")){closeEventPopup()}})}}function openEventPopup(eventId){eventPopup=document.getElementById("eventPopup");if(!eventPopup){console.error("Popup element not found");return}if(!eventPopup.onclick){initPopup()}currentEventId=eventId;const titleEl=document.getElementById("popupTitle");const descEl=document.getElementById("popupDescription");if(titleEl)titleEl.textContent="Loading...";if(descEl)descEl.textContent="";fetch(`/timeline/api/event/${eventId}/`).then(response=>{if(!response.ok){throw new Error("Event not found")}return response.json()}).then(event=>{setPopupContentFromAPI(event);resetAISection();const newUrl=new URL(window.location.href);newUrl.searchParams.set("event",eventId);window.history.pushState({},"",newUrl)}).catch(error=>{console.error("Failed to load event:",error);if(titleEl)titleEl.textContent="Error loading event";if(descEl)descEl.textContent="Please try again."});eventPopup.classList.add("active");document.body.style.overflow="hidden";const closeBtn=eventPopup.querySelector(".popup-close");if(closeBtn){closeBtn.focus()}console.log(`Opened popup for event ${eventId}`)}function openMarkdownEventPopup(element){eventPopup=document.getElementById("eventPopup");if(!eventPopup){console.error("Popup element not found");return}if(!eventPopup.onclick){initPopup()}const titleEl=element.querySelector(".event-title");const categoryEl=element.querySelector(".event-category");const descEl=element.querySelector(".event-description");const title=titleEl?titleEl.textContent:"Untitled Event";const category=categoryEl?categoryEl.textContent:"Other";const description=element.dataset.notes||(descEl?descEl.textContent:"");const date=element.dataset.date||"";let dateDisplay=date;if(date&&date.length>=10){const dateObj=new Date(date);if(!isNaN(dateObj.getTime())){dateDisplay=dateObj.toLocaleDateString("en-US",{year:"numeric",month:"long",day:"numeric"})}}if(document.getElementById("popupTitle")){document.getElementById("popupTitle").textContent=title}if(document.getElementById("popupDate")){document.getElementById("popupDate").textContent=dateDisplay}if(document.getElementById("popupCategory")){document.getElementById("popupCategory").textContent=category}if(document.getElementById("popupDescription")){document.getElementById("popupDescription").textContent=description}const docsContainer=document.getElementById("popupDocs");const mediaSection=document.getElementById("popupMedia");if(docsContainer)docsContainer.innerHTML="";if(mediaSection)mediaSection.style.display="none";resetAISection();eventPopup.classList.add("active");document.body.style.overflow="hidden";const closeBtn=eventPopup.querySelector(".popup-close");if(closeBtn){closeBtn.focus()}console.log(`Opened popup for markdown event: ${title}`)}function setPopupContent(eventId,event){if(!event)return;if(document.getElementById("popupTitle")){document.getElementById("popupTitle").textContent=event.title}if(document.getElementById("popupDate")){document.getElementById("popupDate").textContent=event.date}if(document.getElementById("popupCategory")){document.getElementById("popupCategory").textContent=event.category||"Uncategorized"}if(document.getElementById("popupDescription")){document.getElementById("popupDescription").textContent=event.description}renderDocuments(event)}function setPopupContentFromAPI(event){if(!event)return;if(document.getElementById("popupTitle")){document.getElementById("popupTitle").textContent=event.event||"Untitled"}if(document.getElementById("popupDate")){document.getElementById("popupDate").textContent=event.date_display||event.date}if(document.getElementById("popupCategory")){document.getElementById("popupCategory").textContent=event.category||"Uncategorized"}if(document.getElementById("popupDescription")){document.getElementById("popupDescription").textContent=event.notes||"No notes available."}renderDocumentsFromAPI(event)}function renderDocuments(event){const docsContainer=document.getElementById("popupDocs");const mediaSection=document.getElementById("popupMedia");if(!docsContainer)return;docsContainer.innerHTML="";const evidence=event.evidence||[];if(!evidence||evidence.length===0){if(mediaSection){mediaSection.style.display="none"}return}if(mediaSection){mediaSection.style.display="block"}evidence.forEach((doc,index)=>{const docElement=document.createElement("div");docElement.className="document-item";const docLink=document.createElement("a");docLink.href=doc.file_url||"#";docLink.target="_blank";docLink.rel="noopener noreferrer";let icon="📄";if(doc.file_url){const ext=doc.file_url.split(".").pop().toLowerCase();if(ext==="pdf")icon="📕";else if(["png","jpg","jpeg","gif","webp","svg"].includes(ext))icon="🖼️";else if(["doc","docx"].includes(ext))icon="📝";else if(["xls","xlsx"].includes(ext))icon="📊";else if(["txt","md","markdown"].includes(ext))icon="📄";else if(["email","eml"].includes(ext))icon="✉️"}docLink.innerHTML=`<span class="doc-icon">${icon}</span> <span class="doc-title">${doc.title||"Document "+(index+1)}</span>`;if(doc.size||doc.type){const metaElement=document.createElement("span");metaElement.className="doc-meta";metaElement.textContent=`[${doc.type||"File"}${doc.size?" - "+doc.size:""}]`;docLink.appendChild(metaElement)}docElement.appendChild(docLink);if(doc.url&&isImageUrl(doc.url)){const previewElement=document.createElement("div");previewElement.className="doc-preview";previewElement.innerHTML=`<img src="${doc.url}" alt="${doc.title||"Preview"}" loading="lazy">`;docElement.appendChild(previewElement)}docsContainer.appendChild(docElement)})}function renderDocumentsFromAPI(event){const docsContainer=document.getElementById("popupDocs");const mediaSection=document.getElementById("popupMedia");if(!docsContainer)return;docsContainer.innerHTML="";const evidence=event.evidence||[];if(!evidence||evidence.length===0){if(mediaSection){mediaSection.style.display="none"}return}if(mediaSection){mediaSection.style.display="block"}evidence.forEach((doc,index)=>{const docElement=document.createElement("div");docElement.className="document-item";const docLink=document.createElement("a");docLink.href=doc.file_url||"#";docLink.target="_blank";docLink.rel="noopener noreferrer";let icon="📄";if(doc.url){const ext=doc.url.split(".").pop().toLowerCase();if(ext==="pdf")icon="📕";else if(["png","jpg","jpeg","gif","webp","svg"].includes(ext))icon="🖼️";else if(["doc","docx"].includes(ext))icon="📝";else if(["xls","xlsx"].includes(ext))icon="📊";else if(["txt","md","markdown"].includes(ext))icon="📄";else if(["email","eml"].includes(ext))icon="✉️"}docLink.innerHTML=`<span class="doc-icon">${icon}</span> <span class="doc-title">${doc.title||"Document "+(index+1)}</span>`;docElement.appendChild(docLink);docsContainer.appendChild(docElement)})}function isImageUrl(url){const ext=url.split(".").pop().toLowerCase();return["png","jpg","jpeg","gif","webp","svg","bmp"].includes(ext)}function resetAISection(){const aiSection=document.getElementById("aiSection");const aiResponse=document.getElementById("aiResponse");const aiLoading=document.getElementById("aiLoading");const askAIBtn=document.getElementById("askAIBtn");if(aiSection)aiSection.style.display="none";if(aiResponse)aiResponse.innerHTML="";if(aiLoading)aiLoading.style.display="block";if(askAIBtn){askAIBtn.disabled=false;askAIBtn.innerHTML='<span class="ai-icon">🤖</span> Ask AI About This'}isAnalyzingWithAI=false}function askAIAboutEvent(){if(!currentEventId||isAnalyzingWithAI)return;const askAIBtn=document.getElementById("askAIBtn");const aiSection=document.getElementById("aiSection");const aiResponse=document.getElementById("aiResponse");const aiLoading=document.getElementById("aiLoading");if(!aiSection||!aiResponse||!askAIBtn)return;aiSection.style.display="block";aiResponse.innerHTML="";aiLoading.style.display="block";askAIBtn.disabled=true;askAIBtn.innerHTML='<span class="ai-icon">🤖</span> Analyzing...';isAnalyzingWithAI=true;fetch(`/ai/analyze-event/${currentEventId}/`).then(response=>response.json()).then(data=>{if(data.status==="success"){const formattedResponse=formatMarkdown(data.analysis);aiResponse.innerHTML=formattedResponse;aiLoading.style.display="none";askAIBtn.disabled=false;askAIBtn.innerHTML='<span class="ai-icon">🤖</span> Ask AI Again'}else{aiResponse.innerHTML='<p class="ai-error">Error: '+(data.error||"Failed to get AI analysis")+"</p>";aiLoading.style.display="none";askAIBtn.disabled=false;askAIBtn.innerHTML='<span class="ai-icon">🤖</span> Try Again'}}).catch(error=>{console.error("AI analysis error:",error);aiResponse.innerHTML='<p class="ai-error">Error: Failed to connect to AI service. Please check your configuration.</p>';aiLoading.style.display="none";askAIBtn.disabled=false;askAIBtn.innerHTML='<span class="ai-icon">🤖</span> Try Again'}).finally(()=>{isAnalyzingWithAI=false})}function formatMarkdown(markdown){if(!markdown)return"<p>No response from AI.</p>";let html=markdown.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");html=html.replace(/^#\s+(.*?)$/gm,"<h2>$1</h2>");html=html.replace(/^##\s+(.*?)$/gm,"<h3>$1</h3>");html=html.replace(/^###\s+(.*?)$/gm,"<h4>$1</h4>");html=html.replace(/\*\*(.*?)\*\*/g,"<strong>$1</strong>");html=html.replace(/\*(.*?)\*/g,"<em>$1</em>");html=html.replace(/^\-\s+(.*?)$/gm,"<li>$1</li>");html=html.replace(/^\d+\.\s+(.*?)$/gm,"<li>$1</li>");html=html.replace(/((?:<li>.*<\/li>\n)+)/g,function(match){return"<ul>"+match.trim().replace(/<\/li>\n/g,"</li>")+"</ul>"});html=html.replace(/\n\n+/g,"</p><p>");html=html.replace(/\n/g,"<br>");html="<p>"+html+"</p>";html=html.replace(/`(.*?)`/g,"<code>$1</code>");html=html.replace(/\[(.*?)\]\((.*?)\)/g,'<a href="$2" target="_blank" rel="noopener">$1</a>');html=html.replace(/^---$/gm,"<hr>");html=html.replace(/^>\s+(.*?)$/gm,"<blockquote>$1</blockquote>");return html}function closeEventPopup(){if(!eventPopup){eventPopup=document.getElementById("eventPopup")}if(eventPopup){eventPopup.classList.remove("active");document.body.style.overflow="";resetAISection();currentEventId=null;const newUrl=new URL(window.location.href);newUrl.searchParams.delete("event");window.history.pushState({},"",newUrl);const activeEvent=document.querySelector(".timeline-event:focus");if(activeEvent){activeEvent.blur()}}}function checkUrlForEvent(){const urlParams=new URLSearchParams(window.location.search);const eventId=urlParams.get("event");if(eventId){const uuidRegex=/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;if(uuidRegex.test(eventId)){openEventPopup(eventId)}}}document.addEventListener("DOMContentLoaded",function(){setTimeout(checkUrlForEvent,100)});function closePopup(eventId){closeEventPopup()}function showPopup(eventId){openEventPopup(eventId)}document.addEventListener("DOMContentLoaded",function(){initPopup();document.querySelectorAll('[id^="popup-"]').forEach(popup=>{const closeBtn=popup.querySelector(".popup-close");if(closeBtn){closeBtn.addEventListener("click",()=>{popup.classList.remove("active")})}})});eventPopup=document.getElementById("eventPopup");document.addEventListener("click",function(e){if(eventPopup&&eventPopup.classList.contains("active")){if(!eventPopup.contains(e.target)){closeEventPopup()}}});function testUpdateLogo(){const logo=document.getElementById("site-logo");const html=document.documentElement;if(!logo){console.error("Logo element not found for testing");return false}const originalTheme=html.getAttribute("data-theme");html.setAttribute("data-theme","dark");updateLogo("dark");const darkLogo=logo.src.includes("DARK_mode_LOGO.png");html.setAttribute("data-theme","light");updateLogo("light");const lightLogo=logo.src.includes("light_mode_LOGO.png");html.setAttribute("data-theme",originalTheme);updateLogo(originalTheme);if(darkLogo&&lightLogo){console.log("✓ updateLogo() test passed: Both dark and light logos load correctly");return true}else{console.error("✗ updateLogo() test failed: Logo sources not updated correctly");return false}}function testUpdateIcon(){const toggle=document.getElementById("theme-toggle");const icon=toggle&&toggle.querySelector(".theme-icon");if(!icon){console.error("Icon element not found for testing");return false}updateIcon("dark");const darkIcon=icon.textContent==="☀️";updateIcon("light");const lightIcon=icon.textContent==="🌙";const html=document.documentElement;const currentTheme=html.getAttribute("data-theme");updateIcon(currentTheme);if(darkIcon&&lightIcon){console.log("✓ updateIcon() test passed: Icons toggle correctly");return true}else{console.error("✗ updateIcon() test failed: Icons not updated correctly");return false}}function testTheme(){console.log("Running theme tests...");const logoTest=testUpdateLogo();const iconTest=testUpdateIcon();if(logoTest&&iconTest){console.log("✓ All theme tests passed!");return true}else{console.error("✗ Some theme tests failed");return false}}